 52	func (a *workerDispatchAdapter) DispatchWorker(ctx context.Context, kind string, projectRoot string, rawArgs *string) (*ddxgraphql.WorkerDispatchResult, error) {
 53		if a == nil || a.manager == nil {
 54			return nil, fmt.Errorf("worker dispatcher is not configured")
 55		}
 56		if err := ctx.Err(); err != nil {
 57			return nil, err
 58		}
 59		if kind != "execute-loop" {
 60			return nil, fmt.Errorf("unsupported worker kind %q", kind)
 61		}
 62	
 63		var req struct {
 64			Harness       string `json:"harness"`
 65			Model         string `json:"model"`
 66			Profile       string `json:"profile"`
 67			Provider      string `json:"provider"`
 68			ModelRef      string `json:"model_ref"`
 69			Effort        string `json:"effort"`
 70			LabelFilter   string `json:"label_filter"`
 71			Once          bool   `json:"once"`
 72			PollInterval  string `json:"poll_interval"`
 73			NoReview      bool   `json:"no_review"`
 74			ReviewHarness string `json:"review_harness"`
 75			ReviewModel   string `json:"review_model"`
 76		}
 77		if rawArgs != nil && *rawArgs != "" {
 78			if err := json.Unmarshal([]byte(*rawArgs), &req); err != nil {
 79				return nil, fmt.Errorf("invalid worker args JSON: %w", err)
 80			}
 81		}
 82	
 83		// Apply .ddx/config.yaml workers.default_spec + enforce workers.max_count
 84		// (ddx-b6cf025c). The max_count cap counts currently-running drain workers
 85		// for this project so the "+ Add worker" button can refuse cleanly.
 86		if wc := loadWorkersConfig(projectRoot); wc != nil {
 87			if spec := wc.DefaultSpec; spec != nil {
 88				if req.Harness == "" {
 89					req.Harness = spec.Harness
 90				}
 91				if req.Profile == "" {
 92					req.Profile = spec.Profile
 93				}
 94				if req.Effort == "" {
 95					req.Effort = spec.Effort
 96				}
 97			}
 98			if wc.MaxCount != nil && *wc.MaxCount >= 0 {
 99				running := a.countRunningDrainWorkers(projectRoot)
100				if running >= *wc.MaxCount {
101					return nil, fmt.Errorf("workers.max_count cap reached: %d running (limit %d)", running, *wc.MaxCount)
102				}
103			}
104		}
105	
106		// Default-path contract (ddx-755f5881 AC #1): an empty dispatch input
107		// (no rawArgs, no workers.default_spec) must produce a spec with
108		// Profile: "default" and nothing else. This eliminates the historical
109		// 19-burn drain-queue failure mode where an empty spec fanned out into
110		// per-tier ladder iteration with no upstream synthesis target.
111		if req.Profile == "" {
112			req.Profile = "default"
113		}
114	
115		// Default poll-interval = 30s for server-managed workers (ddx-dc157075).
116		// Operators wanting drain-and-exit semantics must pass --once or an
117		// explicit poll_interval=0 in the dispatch payload.
118		pollInterval := 30 * time.Second
119		if req.PollInterval != "" {
120			d, err := time.ParseDuration(req.PollInterval)
121			if err != nil {
122				return nil, fmt.Errorf("invalid poll_interval: %w", err)
123			}
124			pollInterval = d
125		}
126	
127		record, err := a.manager.StartExecuteLoop(ExecuteLoopWorkerSpec{
128			ProjectRoot:   projectRoot,
129			Harness:       req.Harness,
130			Model:         req.Model,
131			Profile:       req.Profile,
132			Provider:      req.Provider,
133			ModelRef:      req.ModelRef,
134			Effort:        req.Effort,
135			LabelFilter:   req.LabelFilter,
136			Once:          req.Once,
137			PollInterval:  pollInterval,
138			NoReview:      req.NoReview,
139			ReviewHarness: req.ReviewHarness,
140			ReviewModel:   req.ReviewModel,
141		})
142		if err != nil {
143			return nil, err
144		}
145		return &ddxgraphql.WorkerDispatchResult{
